    ha: [["Adireshi","Wurin jama'a da ake amfani da shi domin karbar kadarorin dijital."],["Makullin sirri","Makullin sirri da ke ba ka iko da walat. Kada ka taba rabawa."],["Jimlar dawo da walat","Kalmomin ajiya da ake amfani da su domin dawo da walat. Kada ka taba rabawa."],["Kudin gas","Kudin hanyar sadarwa da ake biya domin a sarrafa kuma a rubuta muamala a kan sarkar bayanai."],["Makullin jama'a","Makullin sirri da ke da alaka da walat kuma yake taimakawa wajen samar da adireshi."],["Mai duba sarkar bayanai","Shafi ko kayan aiki da ke nuna muamala da adireshi a kan sarkar bayanai."],["Kwangilar smart","Lamba ce da ke kan sarkar bayanai wadda ke aiwatar da kanta idan sharuddan da aka sa sun cika."],["Rikon kadara","Wanene ke rike da makullai da ikon shiga kadarori."],["Gada","Kayan aiki da ake amfani da shi wajen motsa kadarori ko sakonni tsakanin sarkokin bayanai daban-daban."],["Sarkar bayanai","Tsarin rajista ne da kwamfutoci da yawa ke kula da shi tare domin a iya duba bayanai ba tare da dogaro da kamfani guda ba."],["Hakowa","Hanya ce da wasu sarkokin bayanai ke amfani da karfin kwamfuta domin tabbatar da muamala da kara sabon tubali."],["Walat","Kayan aiki ne da ke kula da makullanka sannan ya ba ka damar shiga, aikawa, da karbar kadarorin dijital."],["Mataki na 1","Asalin sarkar bayanai ce da ke da nata dokoki, tsaro, da tarihin muamala."],["Muamala a sakan daya","Ma'auni ne da ke nuna yawan muamalar da hanyar sadarwa za ta iya sarrafawa a sakan daya."],["Mai tabbatarwa","Mai shiga hanyar sadarwa da ke taimakawa duba da tabbatar da muamala da tubalan a wasu sarkokin bayanai."],["Tura kudi","Aika kudi daga wuri ko kasa guda zuwa wata, yawanci domin iyali ko kasuwanci."],["Tsakaitawa","Yanayi ne da iko ko yanke hukunci yake taruwa a hannun bangare kadan maimakon ya bazu sosai."],["Musaya","Dandali ne da masu amfani ke saya, sayarwa, ko musayar kadarorin dijital."],["Tokan","Kadara ce ta dijital da aka fitar a kan sarkar bayanai, yawanci tana da takamaiman aiki a wani tsari."],["Tsayayyen kudin dijital","Tokan da aka tsara ya rike kima mai dan kwanciyar hankali, sau da yawa yana bin dala ko wata kudin fiat."],["Daidaitacciyar alaka","Alakar kima da tokan ke kokarin rikewa da wata kadara, misali 1:1 da dalar Amurka."],["Saukakiyar musaya","Yadda saukin saye ko sayar da kadara yake ba tare da canza farashinta sosai ba."],["Tsarin kudi marar tsakiya","Ayyukan kudi ne da ke gudana a kan sarkar bayanai kamar rance, ciniki, da ajiya ba tare da banki na gargajiya a tsakiya ba."],["Lamuni","Bada damar a aro kadara, yawanci tare da jingina ko biyan ruwa."],["Lamunin take","Rance ne da ake aro kuma a biya shi gaba daya a cikin muamala guda a kan sarkar bayanai."],["NFT","Tokan ne na musamman da ke wakiltar mallaka, asali, ko damar shiga ga wani abu na dijital ko na zahiri."],["Fitarwa","Kirkira da fitar da sabon tokan ko NFT a kan sarkar bayanai."],["Tantance ainihi","Hanyar tabbatar da kanka da dandali zai iya bukata kafin a bude dukkan ayyuka."],["Kudin gargajiya","Kudin da gwamnati ke fitarwa kamar dala, yuro, ko naira."],["Walat na kanka","Walat da kake da iko da makullai da bayanan dawowa kai tsaye."],["Airdrop","Tokan da wani aiki ke rabawa, sau da yawa domin tallatawa ko sakamakon shiga al'umma."],["Damfarar kyauta","Yaudara da ke yi kamar tana ba da kyauta domin a sa ka hada walat ko aika kudi tukuna."],["Kalmomin dawowa","Kalmomin dawo da walat. Kada ka taba rabawa, rubutawa kan layi, ko daukar hoto."],["Cire jari","Lokacin da kungiyar aiki ta cire jari ko ta bace ba zato ba tsammani da kudaden masu amfani."],["Gurbatar adireshi","Damfara da ke barin adireshi mai kama da naka a tarihinka domin ka kwafi mara kyau."]],
